import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ConversionResult {
  id: string;
  name: string;
  blob: Blob;
  previewUrl: string;
  size: number;
  format: 'JPG (XL)' | 'JPG (S)' | 'WebP';
  dimensions: { width: number; height: number };
}

export interface ProcessingState {
  isProcessing: boolean;
  progress: number;
  error: string | null;
}

// Use global 'agPsd' and 'JSZip' from CDN scripts
declare const agPsd: any;
declare const JSZip: any;

import { ConversionResult } from '../types';

export const processPsdFile = async (
  file: File,
  onProgress: (progress: number) => void
): Promise<ConversionResult[]> => {
  const buffer = await file.arrayBuffer();
  onProgress(10);

  // Parse PSD
  const psd = agPsd.readPsd(buffer);
  onProgress(30);

  // The main canvas of the PSD
  const originalCanvas = psd.canvas;
  if (!originalCanvas) {
    throw new Error('Could not extract canvas from PSD');
  }

  const { width, height } = originalCanvas;
  const results: ConversionResult[] = [];
  const baseName = file.name.replace(/\.[^/.]+$/, "");

  // Helper to convert canvas to blob
  const getBlob = (canvas: HTMLCanvasElement, type: string, quality: number = 0.9): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      canvas.toBlob((blob) => {
        if (blob) resolve(blob);
        else reject(new Error('Failed to generate blob'));
      }, type, quality);
    });
  };

  // 1. XL JPG (Full size)
  onProgress(50);
  const xlBlob = await getBlob(originalCanvas, 'image/jpeg', 0.95);
  results.push({
    id: 'xl',
    name: `${baseName}_XL.jpg`,
    blob: xlBlob,
    previewUrl: URL.createObjectURL(xlBlob),
    size: xlBlob.size,
    format: 'JPG (XL)',
    dimensions: { width, height }
  });

  // 2. S JPG (Small size - Max width/height 800px)
  onProgress(70);
  const sScale = Math.min(1, 800 / Math.max(width, height));
  const sWidth = Math.round(width * sScale);
  const sHeight = Math.round(height * sScale);

  const sCanvas = document.createElement('canvas');
  sCanvas.width = sWidth;
  sCanvas.height = sHeight;
  const sCtx = sCanvas.getContext('2d');
  if (sCtx) {
    sCtx.imageSmoothingEnabled = true;
    sCtx.imageSmoothingQuality = 'high';
    sCtx.drawImage(originalCanvas, 0, 0, sWidth, sHeight);
  }
  const sBlob = await getBlob(sCanvas, 'image/jpeg', 0.85);
  results.push({
    id: 's',
    name: `${baseName}_S.jpg`,
    blob: sBlob,
    previewUrl: URL.createObjectURL(sBlob),
    size: sBlob.size,
    format: 'JPG (S)',
    dimensions: { width: sWidth, height: sHeight }
  });

  // 3. WebP (Full size)
  onProgress(90);
  const webpBlob = await getBlob(originalCanvas, 'image/webp', 0.9);
  results.push({
    id: 'webp',
    name: `${baseName}.webp`,
    blob: webpBlob,
    previewUrl: URL.createObjectURL(webpBlob),
    size: webpBlob.size,
    format: 'WebP',
    dimensions: { width, height }
  });

  onProgress(100);
  return results;
};

export const createZipPackage = async (results: ConversionResult[], filename: string): Promise<Blob> => {
  const zip = new JSZip();
  results.forEach((res) => {
    zip.file(res.name, res.blob);
  });
  return await zip.generateAsync({ type: 'blob' });
};

import React from 'react';
import { ConversionResult } from '../types';

interface ResultCardProps {
  result: ConversionResult;
}

const ResultCard: React.FC<ResultCardProps> = ({ result }) => {
  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  const handleDownload = () => {
    const link = document.createElement('a');
    link.href = result.previewUrl;
    link.download = result.name;
    link.click();
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col hover:shadow-md transition-shadow">
      <div className="aspect-square bg-slate-100 flex items-center justify-center overflow-hidden">
        <img 
          src={result.previewUrl} 
          alt={result.name} 
          className="object-contain w-full h-full p-2"
        />
      </div>
      <div className="p-4 flex flex-col flex-1">
        <div className="flex items-center justify-between mb-2">
          <span className="text-xs font-bold uppercase tracking-wider text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
            {result.format}
          </span>
          <span className="text-xs text-slate-400">
            {result.dimensions.width} x {result.dimensions.height}
          </span>
        </div>
        <h3 className="text-sm font-medium text-slate-800 truncate mb-1" title={result.name}>
          {result.name}
        </h3>
        <p className="text-xs text-slate-500 mb-4">{formatSize(result.size)}</p>

        <button
          onClick={handleDownload}
          className="mt-auto w-full py-2 bg-slate-800 hover:bg-slate-900 text-white rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
          </svg>
          下載單個
        </button>
      </div>
    </div>
  );
};

export default ResultCard;

