    try {
      const conversionResults = await processPsdFile(file, (p) => {
        setProcessing(prev => ({ ...prev, progress: p }));
      });
      setResults(conversionResults);
      setProcessing(prev => ({ ...prev, isProcessing: false, progress: 100 }));
