// Use global 'agPsd' and 'JSZip' from CDN scripts
declare const agPsd: any;
declare const JSZip: any;

import { ConversionResult, TargetOrientation } from '../types';

export const processPsdFile = async (
  file: File,
  orientation: TargetOrientation,
  onProgress: (progress: number) => void
): Promise<ConversionResult[]> => {
  const arrayBuffer = await file.arrayBuffer();
  onProgress(10);

  // CRITICAL: ag-psd requires a Uint8Array
  const buffer = new Uint8Array(arrayBuffer);
  onProgress(20);

  let psd;
  try {
    // skipLayerData: true makes it much faster and avoids memory issues with many layers
    // we only need the merged composite image
    psd = agPsd.readPsd(buffer, { skipLayerData: true, skipThumbnail: true });
  } catch (err) {
    console.error("PSD Read Error:", err);
    throw new Error('無法讀取此 PSD 檔案，請檢查檔案是否損毀或為不支援的格式。');
  }
  onProgress(40);

  // Create a canvas and draw the PSD composite onto it
  const originalCanvas = document.createElement('canvas');
  originalCanvas.width = psd.width;
  originalCanvas.height = psd.height;

  try {
    agPsd.drawPsd(originalCanvas, psd);
  } catch (err) {
    console.error("PSD Draw Error:", err);
    throw new Error('無法繪製 PSD 內容，此檔案可能使用了不支援的色彩模式（如 CMYK 16-bit）。');
  }

  if (!originalCanvas || originalCanvas.width === 0) {
    throw new Error('無法從 PSD 提取有效的影像內容');
  }

  const origW = originalCanvas.width;
  const origH = originalCanvas.height;
  const aspectRatio = origH / origW;

  const results: ConversionResult[] = [];
  const baseName = file.name.replace(/\.[^/.]+$/, "");

  // Helper to get scaled canvas
  const getScaledCanvas = (targetDim: number): HTMLCanvasElement => {
    let targetW: number, targetH: number;

    if (orientation === 'landscape') {
      targetW = targetDim;
      targetH = Math.round(targetDim * aspectRatio);
    } else {
      targetH = targetDim;
      targetW = Math.round(targetDim / aspectRatio);
    }

    const scaledCanvas = document.createElement('canvas');
    scaledCanvas.width = targetW;
    scaledCanvas.height = targetH;
    const ctx = scaledCanvas.getContext('2d');
    if (ctx) {
      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
      ctx.drawImage(originalCanvas, 0, 0, targetW, targetH);
    }
    return scaledCanvas;
  };

  // Helper to convert canvas to blob
  const getBlob = (canvas: HTMLCanvasElement, type: string, quality: number = 0.9): Promise<Blob> => {
    return new Promise((resolve, reject) => {
      canvas.toBlob((blob) => {
        if (blob) resolve(blob);
        else reject(new Error('生成影像數據失敗'));
      }, type, quality);
    });
  };

  // 1. XL JPG (Fixed 3200px)
  onProgress(60);
  const xlCanvas = getScaledCanvas(3200);
  const xlBlob = await getBlob(xlCanvas, 'image/jpeg', 0.95);
  results.push({
    id: 'xl',
    name: `${baseName}_XL.jpg`,
    blob: xlBlob,
    previewUrl: URL.createObjectURL(xlBlob),
    size: xlBlob.size,
    format: 'JPG (XL)',
    dimensions: { width: xlCanvas.width, height: xlCanvas.height }
  });

  // 2. S JPG (Fixed 1200px)
  onProgress(80);
  const sCanvas = getScaledCanvas(1200);
  const sBlob = await getBlob(sCanvas, 'image/jpeg', 0.85);
  results.push({
    id: 's',
    name: `${baseName}_S.jpg`,
    blob: sBlob,
    previewUrl: URL.createObjectURL(sBlob),
    size: sBlob.size,
    format: 'JPG (S)',
    dimensions: { width: sCanvas.width, height: sCanvas.height }
  });

  // 3. WebP (Fixed 920px)
  onProgress(95);
  const webpCanvas = getScaledCanvas(920);
  const webpBlob = await getBlob(webpCanvas, 'image/webp', 0.9);
  results.push({
    id: 'webp',
    name: `${baseName}.webp`,
    blob: webpBlob,
    previewUrl: URL.createObjectURL(webpBlob),
    size: webpBlob.size,
    format: 'WebP',
    dimensions: { width: webpCanvas.width, height: webpCanvas.height }
  });

  onProgress(100);
  return results;
};

export const createZipPackage = async (
  results: ConversionResult[], 
  onProgress?: (progress: number) => void
): Promise<Blob> => {
  const zip = new JSZip();
  results.forEach((res) => {
    zip.file(res.name, res.blob);
  });

  return await zip.generateAsync({ type: 'blob' }, (metadata: { percent: number }) => {
    if (onProgress) {
      onProgress(Math.round(metadata.percent));
    }
  });
};

