export interface ImageTransform {
  scale: number;
  translateX: number;
  translateY: number;
}

export interface ImageFile {
  id: string;
  file: File;
  preview: string;
  width: number;
  height: number;
  aspectRatio: number;
  transform: ImageTransform;
}

export interface CollageSettings {
  columns: number;
  rows: number;
  gap: number;
  padding: number;
  backgroundColor: string;
  itemAspectRatio: number; // Width / Height ratio for each cell
  quality: number;
  borderRadius: number;
  borderWidth: number;
  borderColor: string;
}

export interface GridDimensions {
  cols: number;
  rows: number;
  cellWidth: number;
  cellHeight: number;
  totalWidth: number;
  totalHeight: number;
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  X,
  Move,
  Square,
  Zap,
  Columns2,
  Image as ImageIcon,
  ChevronRight,
  GripHorizontal
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage } from './utils/image';

const ASPECT_RATIO_PRESETS = [
  { label: '1:1 正方形', value: 1 },
  { label: '4:5 人肖像', value: 0.8 },
  { label: '3:4 傳統', value: 0.75 },
  { label: '2:3 專業', value: 0.66 },
  { label: '16:9 寬螢幕', value: 1.77 },
];

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 2,
    gap: 15,
    padding: 30,
    backgroundColor: '#ffffff',
    itemAspectRatio: 1, // Default 1:1
    quality: 0.95,
    borderRadius: 12,
    borderWidth: 0,
    borderColor: '#ffffff'
  });

  const [isDraggingCanvas, setIsDraggingCanvas] = useState(false);
  const [draggedThumbnailIdx, setDraggedThumbnailIdx] = useState<number | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const selectedImage = images.find(img => img.id === selectedId);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImages: ImageFile[] = [];
    for (const file of files) {
      const url = URL.createObjectURL(file);
      try {
        const img = await loadImage(url);
        newImages.push({
          id: Math.random().toString(36).substr(2, 9),
          file, 
          preview: url, 
          width: img.width, 
          height: img.height, 
          aspectRatio: img.width / img.height,
          transform: { scale: 1, translateX: 0, translateY: 0 }
        });
      } catch (err) {
        console.error("Failed to load image", err);
      }
    }

    setImages(prev => {
      const updated = [...prev, ...newImages];
      // Automatically update rows based on columns if needed
      setSettings(s => ({ ...s, rows: Math.ceil(updated.length / s.columns) }));
      return updated;
    });
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  // Thumbnail Reordering Logic
  const handleDragStart = (index: number) => {
    setDraggedThumbnailIdx(index);
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedThumbnailIdx === null || draggedThumbnailIdx === index) return;

    const newImages = [...images];
    const item = newImages.splice(draggedThumbnailIdx, 1)[0];
    newImages.splice(index, 0, item);

    setDraggedThumbnailIdx(index);
    setImages(newImages);
  };

  const handleDragEnd = () => {
    setDraggedThumbnailIdx(null);
  };

  const drawCollage = useCallback(async () => {
    if (!canvasRef.current || images.length === 0) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Calculate dimensions based on settings
    const baseRes = 1200; // Reference width for high quality
    const cellWidth = baseRes / settings.columns;
    const cellHeight = cellWidth / settings.itemAspectRatio;

    const totalWidth = (settings.columns * cellWidth) + ((settings.columns - 1) * settings.gap) + (settings.padding * 2);
    const totalHeight = (settings.rows * cellHeight) + ((settings.rows - 1) * settings.gap) + (settings.padding * 2);

    canvas.width = totalWidth;
    canvas.height = totalHeight;

    // Background
    ctx.fillStyle = settings.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const imgObj = images[i];

      const x = settings.padding + (col * (cellWidth + settings.gap));
      const y = settings.padding + (row * (cellHeight + settings.gap));

      try {
        const img = await loadImage(imgObj.preview);
        ctx.save();

        // Draw Frame with Radius
        ctx.beginPath();
        if (settings.borderRadius > 0 && (ctx as any).roundRect) {
          (ctx as any).roundRect(x, y, cellWidth, cellHeight, settings.borderRadius);
        } else {
          ctx.rect(x, y, cellWidth, cellHeight);
        }
        ctx.clip();

        // Image Scaling & Translation
        const cellAspect = cellWidth / cellHeight;
        const imgAspect = img.width / img.height;

        let baseScale = imgAspect > cellAspect ? cellHeight / img.height : cellWidth / img.width;
        const finalScale = baseScale * imgObj.transform.scale;

        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        ctx.drawImage(
          img, 
          (x + cellWidth / 2) - drawWidth / 2 + imgObj.transform.translateX, 
          (y + cellHeight / 2) - drawHeight / 2 + imgObj.transform.translateY, 
          drawWidth, 
          drawHeight
        );

        // Highlight selected
        if (selectedId === imgObj.id) {
          ctx.restore();
          ctx.save();
          ctx.strokeStyle = '#6366f1';
          ctx.lineWidth = 12;
          if (settings.borderRadius > 0 && (ctx as any).roundRect) {
            ctx.beginPath();
            (ctx as any).roundRect(x, y, cellWidth, cellHeight, settings.borderRadius);
            ctx.stroke();
          } else {
            ctx.strokeRect(x, y, cellWidth, cellHeight);
          }
        }

        ctx.restore();
      } catch (err) {
        console.error("Failed image draw", i, err);
      }
    }
  }, [images, settings, selectedId]);

  useEffect(() => {
    drawCollage();
  }, [drawCollage]);

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;
    const cx = (clientX - rect.left) * scaleX;
    const cy = (clientY - rect.top) * scaleY;

    // Simple cell detection
    const baseRes = 1200 / settings.columns;
    const cellWidth = baseRes;
    const cellHeight = cellWidth / settings.itemAspectRatio;

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const x = settings.padding + (col * (cellWidth + settings.gap));
      const y = settings.padding + (row * (cellHeight + settings.gap));

      if (cx >= x && cx <= x + cellWidth && cy >= y && cy <= y + cellHeight) {
        setSelectedId(images[i].id);
        setIsDraggingCanvas(true);
        dragStartRef.current = { 
          x: cx, 
          y: cy, 
          initialX: images[i].transform.translateX, 
          initialY: images[i].transform.translateY 
        };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDraggingCanvas || !dragStartRef.current || !selectedId) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current!.width / rect.width;
    const scaleY = canvasRef.current!.height / rect.height;
    const cx = (clientX - rect.left) * scaleX;
    const cy = (clientY - rect.top) * scaleY;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + (cx - dragStartRef.current.x),
      translateY: dragStartRef.current.initialY + (cy - dragStartRef.current.y)
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDraggingCanvas(false);
    dragStartRef.current = null;
  };

  const downloadCollage = () => {
    if (!canvasRef.current) return;
    const link = document.createElement('a');
    link.download = `stitcher-collage-${Date.now()}.jpg`;
    link.href = canvasRef.current.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#0B0E14] text-slate-100">
      {/* Sidebar - Controls */}
      <aside className="w-full lg:w-80 bg-[#161B22] border-r border-slate-800 overflow-y-auto p-6 space-y-8 scrollbar-hide h-screen hidden lg:block">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-600/20">
            <LayoutGrid className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-black tracking-tight text-white italic">STITCHER</h1>
        </div>

        <section className="space-y-6">
          <div className="space-y-4">
            <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500 flex items-center gap-2">
              <Settings2 className="w-3.5 h-3.5" /> 版面網格 Layout
            </h2>
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <label className="text-[10px] text-slate-400 font-bold ml-1">欄位 (Cols)</label>
                <input 
                  type="number" 
                  min="1" 
                  value={settings.columns} 
                  onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1), rows: Math.ceil(images.length / (parseInt(e.target.value) || 1)) }))} 
                  className="w-full bg-[#0D1117] border border-slate-700 rounded-xl p-2.5 text-sm outline-none focus:border-indigo-500 transition-colors" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] text-slate-400 font-bold ml-1">列數 (Rows)</label>
                <input 
                  type="number" 
                  min="1" 
                  value={settings.rows} 
                  onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))} 
                  className="w-full bg-[#0D1117] border border-slate-700 rounded-xl p-2.5 text-sm outline-none focus:border-indigo-500 transition-colors" 
                />
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500">內部框架比例</h2>
            <div className="grid grid-cols-1 gap-2">
              {ASPECT_RATIO_PRESETS.map((p) => (
                <button 
                  key={p.label}
                  onClick={() => setSettings(s => ({ ...s, itemAspectRatio: p.value }))}
                  className={`flex items-center justify-between px-4 py-2.5 rounded-xl border transition-all text-xs ${
                    settings.itemAspectRatio === p.value 
                      ? 'bg-indigo-600 border-indigo-600 text-white font-bold' 
                      : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {p.label}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
             <div className="flex justify-between items-center">
              <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500">細節微調</h2>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>間距 (Gap)</span>
                  <span>{settings.gap}px</span>
                </div>
                <input type="range" min="0" max="100" value={settings.gap} onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>圓角 (Radius)</span>
                  <span>{settings.borderRadius}px</span>
                </div>
                <input type="range" min="0" max="100" value={settings.borderRadius} onChange={e => setSettings(s => ({ ...s, borderRadius: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>外距 (Padding)</span>
                  <span>{settings.padding}px</span>
                </div>
                <input type="range" min="0" max="150" value={settings.padding} onChange={e => setSettings(s => ({ ...s, padding: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500 block">背景底色</label>
            <div className="flex gap-3 p-2 bg-[#0D1117] border border-slate-700 rounded-xl">
              <input type="color" value={settings.backgroundColor} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="w-10 h-10 bg-transparent border-none cursor-pointer rounded-lg overflow-hidden shrink-0" />
              <input type="text" value={settings.backgroundColor.toUpperCase()} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="flex-1 bg-transparent border-none text-xs font-mono focus:outline-none uppercase text-slate-300" />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-bottom-2">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <Move className="w-3.5 h-3.5" /> 影像調整
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white"><X className="w-4 h-4" /></button>
            </div>
            <div className="space-y-3">
              <div className="flex justify-between text-[10px] font-bold text-slate-400">
                <span>縮放 Scale</span>
                <span>x{selectedImage.transform.scale.toFixed(2)}</span>
              </div>
              <input type="range" min="0.5" max="4" step="0.01" value={selectedImage.transform.scale} onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
              <button onClick={() => updateImageTransform(selectedImage.id, { scale: 1, translateX: 0, translateY: 0 })} className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-[10px] uppercase font-bold text-slate-300 transition rounded-lg">重設位置</button>
            </div>
          </section>
        )}

        <div className="pt-8 mt-4 border-t border-slate-800">
          <button onClick={downloadCollage} disabled={images.length === 0} className="w-full flex items-center justify-center gap-2 py-4 px-6 rounded-2xl bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed font-black text-white transition-all shadow-xl shadow-indigo-600/30 uppercase tracking-widest text-sm">
            <Download className="w-5 h-5" /> 輸出成品
          </button>
        </div>
      </aside>

      {/* Main Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-[#0D1117]">
        <header className="px-6 py-4 bg-[#161B22] border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-4">
            <LayoutGrid className="w-5 h-5 text-indigo-500 lg:hidden" />
            <h2 className="font-black tracking-tight text-sm uppercase text-slate-400">畫布中心</h2>
            <div className="h-4 w-px bg-slate-800 hidden md:block" />
            <div className="hidden md:flex items-center gap-2 text-[11px] text-slate-500 font-medium">
              <span>{images.length} 張圖片</span>
              <ChevronRight className="w-3 h-3" />
              <span>{settings.columns} x {settings.rows} 網格</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <label className="cursor-pointer group">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-full text-xs font-black transition-all shadow-lg shadow-indigo-600/20 group-hover:scale-105 active:scale-95">
                <Upload className="w-4 h-4" />
                <span>加入素材</span>
              </div>
            </label>
          </div>
        </header>

        {/* Canvas Area */}
        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[#0D1117] custom-scrollbar">
          {images.length === 0 ? (
            <div className="text-center space-y-6 max-w-sm">
              <div className="w-20 h-20 bg-[#161B22] rounded-3xl flex items-center justify-center mx-auto border border-slate-800 shadow-2xl">
                <ImageIcon className="w-8 h-8 text-slate-600" />
              </div>
              <div className="space-y-2">
                <h3 className="text-lg font-black text-white uppercase tracking-widest">點擊加入照片</h3>
                <p className="text-slate-500 text-xs px-6 leading-relaxed">上傳多張 JPG/PNG 素材，在下方橫幅拖拽調整順序，左側調整框架細節。</p>
              </div>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_80px_160px_-40px_rgba(0,0,0,0.9)] rounded-md overflow-hidden border border-white/5 transition-transform duration-500">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDraggingCanvas ? 'grabbing' : 'crosshair' }}
                  className="max-w-full max-h-[75vh] object-contain mx-auto select-none touch-none bg-black"
                />
              </div>
              <div className="absolute -top-12 right-0 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => { setImages([]); setSelectedId(null); }} className="flex items-center gap-2 px-4 py-2 bg-red-600/90 hover:bg-red-600 text-white text-[10px] font-black rounded-full shadow-2xl transition backdrop-blur-md uppercase">
                  <Trash2 className="w-3.5 h-3.5" /> 清空畫布
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Bottom Banner - Reorderable Thumbnails */}
        {images.length > 0 && (
          <div className="h-32 bg-[#161B22] border-t border-slate-800 px-6 py-4 flex gap-4 overflow-x-auto items-center scrollbar-hide relative shadow-[0_-20px_50px_rgba(0,0,0,0.3)]">
            <div className="shrink-0 flex items-center gap-2 mr-2">
              <GripHorizontal className="w-4 h-4 text-slate-600" />
              <span className="text-[10px] font-black text-slate-500 uppercase vertical-text">排序</span>
            </div>

            {images.map((img, index) => (
              <div 
                key={img.id} 
                draggable
                onDragStart={() => handleDragStart(index)}
                onDragOver={(e) => handleDragOver(e, index)}
                onDragEnd={handleDragEnd}
                className={`relative flex-shrink-0 group cursor-grab active:cursor-grabbing transition-all duration-300 ${
                  draggedThumbnailIdx === index ? 'opacity-30 scale-90' : 'opacity-100'
                }`}
              >
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-16 w-16 overflow-hidden rounded-xl border-2 transition-all duration-300 ${
                    selectedId === img.id ? 'border-indigo-500 ring-4 ring-indigo-500/20 scale-105 shadow-xl' : 'border-slate-800 hover:border-slate-500'
                  }`}
                >
                  <img src={img.preview} alt="Thumb" className="h-full w-full object-cover select-none pointer-events-none" />
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(img.id); }} 
                  className="absolute -top-2 -right-2 p-1.5 bg-slate-900 border border-slate-700 text-white rounded-full transition opacity-0 group-hover:opacity-100 scale-75 hover:bg-red-600 hover:border-red-600 shadow-xl"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}

            <label className="flex-shrink-0 h-16 w-16 flex items-center justify-center border-2 border-dashed border-slate-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition-all">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex flex-col items-center gap-1">
                <Upload className="w-4 h-4 text-slate-600" />
                <span className="text-[8px] font-bold text-slate-600">ADD</span>
              </div>
            </label>
          </div>
        )}
      </main>

      <style>{`
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; }
        .vertical-text { writing-mode: vertical-rl; transform: rotate(180deg); }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  X,
  Move,
  Image as ImageIcon,
  ChevronRight,
  GripHorizontal
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage } from './utils/image';

const ASPECT_RATIO_PRESETS = [
  { label: '1:1 正方形', value: 1 },
  { label: '4:5 人肖像', value: 0.8 },
  { label: '3:4 傳統', value: 0.75 },
  { label: '2:3 專業', value: 0.66 },
  { label: '16:9 寬螢幕', value: 1.77 },
];

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 2,
    gap: 15,
    padding: 30,
    backgroundColor: '#ffffff',
    itemAspectRatio: 1, 
    quality: 0.95,
    borderRadius: 12,
    borderWidth: 0,
    borderColor: '#ffffff'
  });

  const [isDraggingCanvas, setIsDraggingCanvas] = useState(false);
  const [draggedThumbnailIdx, setDraggedThumbnailIdx] = useState<number | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const selectedImage = images.find(img => img.id === selectedId);

  // Core drawing logic separated from state to allow export without highlights
  const renderCollage = async (
    canvas: HTMLCanvasElement, 
    imageList: ImageFile[], 
    config: CollageSettings, 
    highlightId: string | null
  ) => {
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const baseRes = 1200; 
    const cellWidth = baseRes / config.columns;
    const cellHeight = cellWidth / config.itemAspectRatio;

    const totalWidth = (config.columns * cellWidth) + ((config.columns - 1) * config.gap) + (config.padding * 2);
    const totalHeight = (config.rows * cellHeight) + ((config.rows - 1) * config.gap) + (config.padding * 2);

    canvas.width = totalWidth;
    canvas.height = totalHeight;

    ctx.fillStyle = config.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < imageList.length; i++) {
      const col = i % config.columns;
      const row = Math.floor(i / config.columns);
      const imgObj = imageList[i];

      const x = config.padding + (col * (cellWidth + config.gap));
      const y = config.padding + (row * (cellHeight + config.gap));

      try {
        const img = await loadImage(imgObj.preview);
        ctx.save();

        ctx.beginPath();
        if (config.borderRadius > 0 && (ctx as any).roundRect) {
          (ctx as any).roundRect(x, y, cellWidth, cellHeight, config.borderRadius);
        } else {
          ctx.rect(x, y, cellWidth, cellHeight);
        }
        ctx.clip();

        const cellAspect = cellWidth / cellHeight;
        const imgAspect = img.width / img.height;

        let baseScale = imgAspect > cellAspect ? cellHeight / img.height : cellWidth / img.width;
        const finalScale = baseScale * imgObj.transform.scale;

        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        ctx.drawImage(
          img, 
          (x + cellWidth / 2) - drawWidth / 2 + imgObj.transform.translateX, 
          (y + cellHeight / 2) - drawHeight / 2 + imgObj.transform.translateY, 
          drawWidth, 
          drawHeight
        );

        // Only Draw Highlight if NOT exporting (highlightId is not null)
        if (highlightId === imgObj.id) {
          ctx.restore();
          ctx.save();
          ctx.strokeStyle = '#6366f1';
          ctx.lineWidth = 14; 
          if (config.borderRadius > 0 && (ctx as any).roundRect) {
            ctx.beginPath();
            (ctx as any).roundRect(x, y, cellWidth, cellHeight, config.borderRadius);
            ctx.stroke();
          } else {
            ctx.strokeRect(x, y, cellWidth, cellHeight);
          }
        }

        ctx.restore();
      } catch (err) {
        console.error("Failed image draw", i, err);
      }
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImages: ImageFile[] = [];
    for (const file of files) {
      const url = URL.createObjectURL(file);
      try {
        const img = await loadImage(url);
        newImages.push({
          id: Math.random().toString(36).substr(2, 9),
          file, 
          preview: url, 
          width: img.width, 
          height: img.height, 
          aspectRatio: img.width / img.height,
          transform: { scale: 1, translateX: 0, translateY: 0 }
        });
      } catch (err) {
        console.error("Failed to load image", err);
      }
    }

    setImages(prev => {
      const updated = [...prev, ...newImages];
      setSettings(s => ({ ...s, rows: Math.ceil(updated.length / s.columns) }));
      return updated;
    });
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const handleDragStart = (index: number) => {
    setDraggedThumbnailIdx(index);
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedThumbnailIdx === null || draggedThumbnailIdx === index) return;

    const newImages = [...images];
    const item = newImages.splice(draggedThumbnailIdx, 1)[0];
    newImages.splice(index, 0, item);

    setDraggedThumbnailIdx(index);
    setImages(newImages);
  };

  const handleDragEnd = () => {
    setDraggedThumbnailIdx(null);
  };

  const drawPreview = useCallback(() => {
    if (!canvasRef.current || images.length === 0) return;
    renderCollage(canvasRef.current, images, settings, selectedId);
  }, [images, settings, selectedId]);

  useEffect(() => {
    drawPreview();
  }, [drawPreview]);

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;
    const cx = (clientX - rect.left) * scaleX;
    const cy = (clientY - rect.top) * scaleY;

    const baseRes = 1200 / settings.columns;
    const cellWidth = baseRes;
    const cellHeight = cellWidth / settings.itemAspectRatio;

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const x = settings.padding + (col * (cellWidth + settings.gap));
      const y = settings.padding + (row * (cellHeight + settings.gap));

      if (cx >= x && cx <= x + cellWidth && cy >= y && cy <= y + cellHeight) {
        setSelectedId(images[i].id);
        setIsDraggingCanvas(true);
        dragStartRef.current = { 
          x: cx, 
          y: cy, 
          initialX: images[i].transform.translateX, 
          initialY: images[i].transform.translateY 
        };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDraggingCanvas || !dragStartRef.current || !selectedId) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current!.width / rect.width;
    const scaleY = canvasRef.current!.height / rect.height;
    const cx = (clientX - rect.left) * scaleX;
    const cy = (clientY - rect.top) * scaleY;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + (cx - dragStartRef.current.x),
      translateY: dragStartRef.current.initialY + (cy - dragStartRef.current.y)
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDraggingCanvas(false);
    dragStartRef.current = null;
  };

  const downloadCollage = async () => {
    if (!canvasRef.current) return;

    // Create a temporary canvas for a clean export
    const exportCanvas = document.createElement('canvas');
    await renderCollage(exportCanvas, images, settings, null); // null highlightId means no highlight drawn

    const link = document.createElement('a');
    link.download = `stitcher-collage-${Date.now()}.jpg`;
    link.href = exportCanvas.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#0B0E14] text-slate-100">
      {/* Sidebar - Controls */}
      <aside className="w-full lg:w-80 bg-[#161B22] border-r border-slate-800 overflow-y-auto p-6 space-y-8 scrollbar-hide h-screen hidden lg:block">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-600/20">
            <LayoutGrid className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-black tracking-tight text-white italic">STITCHER</h1>
        </div>

        <section className="space-y-6">
          <div className="space-y-4">
            <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500 flex items-center gap-2">
              <Settings2 className="w-3.5 h-3.5" /> 版面網格 Layout
            </h2>
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <label className="text-[10px] text-slate-400 font-bold ml-1">欄位 (Cols)</label>
                <input 
                  type="number" 
                  min="1" 
                  value={settings.columns} 
                  onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1), rows: Math.ceil(images.length / (parseInt(e.target.value) || 1)) }))} 
                  className="w-full bg-[#0D1117] border border-slate-700 rounded-xl p-2.5 text-sm outline-none focus:border-indigo-500 transition-colors" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] text-slate-400 font-bold ml-1">列數 (Rows)</label>
                <input 
                  type="number" 
                  min="1" 
                  value={settings.rows} 
                  onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))} 
                  className="w-full bg-[#0D1117] border border-slate-700 rounded-xl p-2.5 text-sm outline-none focus:border-indigo-500 transition-colors" 
                />
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500">內部框架比例</h2>
            <div className="grid grid-cols-1 gap-2">
              {ASPECT_RATIO_PRESETS.map((p) => (
                <button 
                  key={p.label}
                  onClick={() => setSettings(s => ({ ...s, itemAspectRatio: p.value }))}
                  className={`flex items-center justify-between px-4 py-2.5 rounded-xl border transition-all text-xs ${
                    settings.itemAspectRatio === p.value 
                      ? 'bg-indigo-600 border-indigo-600 text-white font-bold' 
                      : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {p.label}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
             <div className="flex justify-between items-center">
              <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500">細節微調</h2>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>間距 (Gap)</span>
                  <span>{settings.gap}px</span>
                </div>
                <input type="range" min="0" max="100" value={settings.gap} onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>圓角 (Radius)</span>
                  <span>{settings.borderRadius}px</span>
                </div>
                <input type="range" min="0" max="100" value={settings.borderRadius} onChange={e => setSettings(s => ({ ...s, borderRadius: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>外距 (Padding)</span>
                  <span>{settings.padding}px</span>
                </div>
                <input type="range" min="0" max="150" value={settings.padding} onChange={e => setSettings(s => ({ ...s, padding: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500 block">背景底色</label>
            <div className="flex gap-3 p-2 bg-[#0D1117] border border-slate-700 rounded-xl">
              <input type="color" value={settings.backgroundColor} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="w-10 h-10 bg-transparent border-none cursor-pointer rounded-lg overflow-hidden shrink-0" />
              <input type="text" value={settings.backgroundColor.toUpperCase()} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="flex-1 bg-transparent border-none text-xs font-mono focus:outline-none uppercase text-slate-300" />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-bottom-2">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <Move className="w-3.5 h-3.5" /> 影像調整
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white"><X className="w-4 h-4" /></button>
            </div>
            <div className="space-y-3">
              <div className="flex justify-between text-[10px] font-bold text-slate-400">
                <span>縮放 Scale</span>
                <span>x{selectedImage.transform.scale.toFixed(2)}</span>
              </div>
              <input type="range" min="0.5" max="4" step="0.01" value={selectedImage.transform.scale} onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
              <button onClick={() => updateImageTransform(selectedImage.id, { scale: 1, translateX: 0, translateY: 0 })} className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-[10px] uppercase font-bold text-slate-300 transition rounded-lg">重設位置</button>
            </div>
          </section>
        )}
      </aside>

      {/* Main Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-[#0D1117]">
        <header className="px-6 py-4 bg-[#161B22] border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-4">
            <LayoutGrid className="w-5 h-5 text-indigo-500 lg:hidden" />
            <h2 className="font-black tracking-tight text-sm uppercase text-slate-400">畫布中心</h2>
            <div className="h-4 w-px bg-slate-800 hidden md:block" />
            <div className="hidden md:flex items-center gap-2 text-[11px] text-slate-500 font-medium">
              <span>{images.length} 張圖片</span>
              <ChevronRight className="w-3 h-3" />
              <span>{settings.columns} x {settings.rows} 網格</span>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <label className="cursor-pointer group">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-4 py-2.5 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-full text-xs font-bold text-slate-300 transition-all active:scale-95">
                <Upload className="w-3.5 h-3.5" />
                <span>加入素材</span>
              </div>
            </label>
            <button 
              onClick={downloadCollage} 
              disabled={images.length === 0}
              className="flex items-center gap-2 px-6 py-2.5 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed rounded-full text-xs font-black text-white transition-all shadow-lg shadow-indigo-600/30 active:scale-95"
            >
              <Download className="w-4 h-4" />
              <span>輸出成品</span>
            </button>
          </div>
        </header>

        {/* Canvas Area */}
        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[#0D1117] custom-scrollbar">
          {images.length === 0 ? (
            <div className="text-center space-y-6 max-w-sm">
              <div className="w-20 h-20 bg-[#161B22] rounded-3xl flex items-center justify-center mx-auto border border-slate-800 shadow-2xl">
                <ImageIcon className="w-8 h-8 text-slate-600" />
              </div>
              <div className="space-y-2">
                <h3 className="text-lg font-black text-white uppercase tracking-widest">點擊加入照片</h3>
                <p className="text-slate-500 text-xs px-6 leading-relaxed">上傳多張 JPG/PNG 素材，在下方橫幅拖拽調整順序，左側調整框架細節。</p>
              </div>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_80px_160px_-40px_rgba(0,0,0,0.9)] rounded-md overflow-hidden border border-white/5 transition-transform duration-500">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDraggingCanvas ? 'grabbing' : 'crosshair' }}
                  className="max-w-full max-h-[75vh] object-contain mx-auto select-none touch-none bg-black"
                />
              </div>
              <div className="absolute -top-12 right-0 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => { setImages([]); setSelectedId(null); }} className="flex items-center gap-2 px-4 py-2 bg-red-600/90 hover:bg-red-600 text-white text-[10px] font-black rounded-full shadow-2xl transition backdrop-blur-md uppercase">
                  <Trash2 className="w-3.5 h-3.5" /> 清空畫布
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Bottom Banner - Reorderable Thumbnails */}
        {images.length > 0 && (
          <div className="h-32 bg-[#161B22] border-t border-slate-800 px-6 py-4 flex gap-4 overflow-x-auto items-center scrollbar-hide relative shadow-[0_-20px_50px_rgba(0,0,0,0.3)]">
            <div className="shrink-0 flex items-center gap-2 mr-2">
              <GripHorizontal className="w-4 h-4 text-slate-600" />
              <span className="text-[10px] font-black text-slate-500 uppercase vertical-text">排序</span>
            </div>

            {images.map((img, index) => (
              <div 
                key={img.id} 
                draggable
                onDragStart={() => handleDragStart(index)}
                onDragOver={(e) => handleDragOver(e, index)}
                onDragEnd={handleDragEnd}
                className={`relative flex-shrink-0 group cursor-grab active:cursor-grabbing transition-all duration-300 ${
                  draggedThumbnailIdx === index ? 'opacity-30 scale-90' : 'opacity-100'
                }`}
              >
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-16 w-16 overflow-hidden rounded-xl border-2 transition-all duration-300 ${
                    selectedId === img.id ? 'border-indigo-500 ring-4 ring-indigo-500/20 scale-105 shadow-xl' : 'border-slate-800 hover:border-slate-500'
                  }`}
                >
                  <img src={img.preview} alt="Thumb" className="h-full w-full object-cover select-none pointer-events-none" />
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(img.id); }} 
                  className="absolute -top-2 -right-2 p-1.5 bg-slate-900 border border-slate-700 text-white rounded-full transition opacity-0 group-hover:opacity-100 scale-75 hover:bg-red-600 hover:border-red-600 shadow-xl"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}

            <label className="flex-shrink-0 h-16 w-16 flex items-center justify-center border-2 border-dashed border-slate-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition-all">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex flex-col items-center gap-1">
                <Upload className="w-4 h-4 text-slate-600" />
                <span className="text-[8px] font-bold text-slate-600">ADD</span>
              </div>
            </label>
          </div>
        )}
      </main>

      <style>{`
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; }
        .vertical-text { writing-mode: vertical-rl; transform: rotate(180deg); }
      `}</style>
    </div>
  );
};

export default App;

export interface ImageTransform {
  scale: number;
  translateX: number;
  translateY: number;
  flipX: boolean;
  flipY: boolean;
}

export interface ImageFile {
  id: string;
  file: File;
  preview: string;
  width: number;
  height: number;
  aspectRatio: number;
  transform: ImageTransform;
}

export interface CollageSettings {
  columns: number;
  rows: number;
  gap: number;
  padding: number;
  backgroundColor: string;
  itemAspectRatio: number; // Width / Height ratio for each cell
  quality: number;
  borderRadius: number;
  borderWidth: number;
  borderColor: string;
}

export interface GridDimensions {
  cols: number;
  rows: number;
  cellWidth: number;
  cellHeight: number;
  totalWidth: number;
  totalHeight: number;
}

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  Upload, 
  Download, 
  Trash2, 
  LayoutGrid, 
  Settings2, 
  X,
  Move,
  Image as ImageIcon,
  ChevronRight,
  GripHorizontal,
  FlipHorizontal,
  FlipVertical,
  RotateCcw
} from 'lucide-react';
import { ImageFile, CollageSettings, ImageTransform } from './types';
import { loadImage } from './utils/image';

const ASPECT_RATIO_PRESETS = [
  { label: '1:1 正方形', value: 1 },
  { label: '4:5 人肖像', value: 0.8 },
  { label: '3:4 傳統', value: 0.75 },
  { label: '2:3 專業', value: 0.66 },
  { label: '16:9 寬螢幕', value: 1.77 },
];

const App: React.FC = () => {
  const [images, setImages] = useState<ImageFile[]>([]);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [settings, setSettings] = useState<CollageSettings>({
    columns: 2,
    rows: 2,
    gap: 15,
    padding: 30,
    backgroundColor: '#ffffff',
    itemAspectRatio: 1, 
    quality: 0.95,
    borderRadius: 12,
    borderWidth: 0,
    borderColor: '#ffffff'
  });

  const [isDraggingCanvas, setIsDraggingCanvas] = useState(false);
  const [draggedThumbnailIdx, setDraggedThumbnailIdx] = useState<number | null>(null);

  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dragStartRef = useRef<{ x: number, y: number, initialX: number, initialY: number } | null>(null);

  const selectedImage = images.find(img => img.id === selectedId);

  // Core drawing logic separated from state to allow export without highlights
  const renderCollage = async (
    canvas: HTMLCanvasElement, 
    imageList: ImageFile[], 
    config: CollageSettings, 
    highlightId: string | null
  ) => {
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const baseRes = 1200; 
    const cellWidth = baseRes / config.columns;
    const cellHeight = cellWidth / config.itemAspectRatio;

    const totalWidth = (config.columns * cellWidth) + ((config.columns - 1) * config.gap) + (config.padding * 2);
    const totalHeight = (config.rows * cellHeight) + ((config.rows - 1) * config.gap) + (config.padding * 2);

    canvas.width = totalWidth;
    canvas.height = totalHeight;

    ctx.fillStyle = config.backgroundColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < imageList.length; i++) {
      const col = i % config.columns;
      const row = Math.floor(i / config.columns);
      const imgObj = imageList[i];

      const x = config.padding + (col * (cellWidth + config.gap));
      const y = config.padding + (row * (cellHeight + config.gap));

      try {
        const img = await loadImage(imgObj.preview);
        ctx.save();

        // Draw Frame with Radius (Clipping)
        ctx.beginPath();
        if (config.borderRadius > 0 && (ctx as any).roundRect) {
          (ctx as any).roundRect(x, y, cellWidth, cellHeight, config.borderRadius);
        } else {
          ctx.rect(x, y, cellWidth, cellHeight);
        }
        ctx.clip();

        const cellAspect = cellWidth / cellHeight;
        const imgAspect = img.width / img.height;

        let baseScale = imgAspect > cellAspect ? cellHeight / img.height : cellWidth / img.width;
        const finalScale = baseScale * imgObj.transform.scale;

        const drawWidth = img.width * finalScale;
        const drawHeight = img.height * finalScale;

        // Image Translation and Mirroring
        const centerX = x + cellWidth / 2 + imgObj.transform.translateX;
        const centerY = y + cellHeight / 2 + imgObj.transform.translateY;

        ctx.translate(centerX, centerY);
        ctx.scale(imgObj.transform.flipX ? -1 : 1, imgObj.transform.flipY ? -1 : 1);

        ctx.drawImage(
          img, 
          -drawWidth / 2, 
          -drawHeight / 2, 
          drawWidth, 
          drawHeight
        );

        ctx.restore();

        // Only Draw Highlight if NOT exporting (highlightId is not null)
        if (highlightId === imgObj.id) {
          ctx.save();
          ctx.strokeStyle = '#6366f1';
          ctx.lineWidth = 14; 
          if (config.borderRadius > 0 && (ctx as any).roundRect) {
            ctx.beginPath();
            (ctx as any).roundRect(x, y, cellWidth, cellHeight, config.borderRadius);
            ctx.stroke();
          } else {
            ctx.strokeRect(x, y, cellWidth, cellHeight);
          }
          ctx.restore();
        }

      } catch (err) {
        console.error("Failed image draw", i, err);
      }
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImages: ImageFile[] = [];
    for (const file of files) {
      const url = URL.createObjectURL(file);
      try {
        const img = await loadImage(url);
        newImages.push({
          id: Math.random().toString(36).substr(2, 9),
          file, 
          preview: url, 
          width: img.width, 
          height: img.height, 
          aspectRatio: img.width / img.height,
          transform: { scale: 1, translateX: 0, translateY: 0, flipX: false, flipY: false }
        });
      } catch (err) {
        console.error("Failed to load image", err);
      }
    }

    setImages(prev => {
      const updated = [...prev, ...newImages];
      setSettings(s => ({ ...s, rows: Math.ceil(updated.length / s.columns) }));
      return updated;
    });
  };

  const updateImageTransform = (id: string, updates: Partial<ImageTransform>) => {
    setImages(prev => prev.map(img => 
      img.id === id ? { ...img, transform: { ...img.transform, ...updates } } : img
    ));
  };

  const removeImage = (id: string) => {
    if (selectedId === id) setSelectedId(null);
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const handleDragStart = (index: number) => {
    setDraggedThumbnailIdx(index);
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (draggedThumbnailIdx === null || draggedThumbnailIdx === index) return;

    const newImages = [...images];
    const item = newImages.splice(draggedThumbnailIdx, 1)[0];
    newImages.splice(index, 0, item);

    setDraggedThumbnailIdx(index);
    setImages(newImages);
  };

  const handleDragEnd = () => {
    setDraggedThumbnailIdx(null);
  };

  const drawPreview = useCallback(() => {
    if (!canvasRef.current || images.length === 0) return;
    renderCollage(canvasRef.current, images, settings, selectedId);
  }, [images, settings, selectedId]);

  useEffect(() => {
    drawPreview();
  }, [drawPreview]);

  const handleCanvasMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!canvasRef.current || images.length === 0) return;
    const rect = canvasRef.current.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current.width / rect.width;
    const scaleY = canvasRef.current.height / rect.height;
    const cx = (clientX - rect.left) * scaleX;
    const cy = (clientY - rect.top) * scaleY;

    const baseRes = 1200 / settings.columns;
    const cellWidth = baseRes;
    const cellHeight = cellWidth / settings.itemAspectRatio;

    for (let i = 0; i < images.length; i++) {
      const col = i % settings.columns;
      const row = Math.floor(i / settings.columns);
      const x = settings.padding + (col * (cellWidth + settings.gap));
      const y = settings.padding + (row * (cellHeight + settings.gap));

      if (cx >= x && cx <= x + cellWidth && cy >= y && cy <= y + cellHeight) {
        setSelectedId(images[i].id);
        setIsDraggingCanvas(true);
        dragStartRef.current = { 
          x: cx, 
          y: cy, 
          initialX: images[i].transform.translateX, 
          initialY: images[i].transform.translateY 
        };
        break;
      }
    }
  };

  const handleCanvasMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDraggingCanvas || !dragStartRef.current || !selectedId) return;
    const rect = canvasRef.current!.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const scaleX = canvasRef.current!.width / rect.width;
    const scaleY = canvasRef.current!.height / rect.height;
    const cx = (clientX - rect.left) * scaleX;
    const cy = (clientY - rect.top) * scaleY;

    updateImageTransform(selectedId, {
      translateX: dragStartRef.current.initialX + (cx - dragStartRef.current.x),
      translateY: dragStartRef.current.initialY + (cy - dragStartRef.current.y)
    });
  };

  const handleCanvasMouseUp = () => {
    setIsDraggingCanvas(false);
    dragStartRef.current = null;
  };

  const downloadCollage = async () => {
    if (images.length === 0) return;

    // Create a temporary canvas for a clean export
    const exportCanvas = document.createElement('canvas');
    await renderCollage(exportCanvas, images, settings, null); // null highlightId means no highlight drawn

    const link = document.createElement('a');
    link.download = `stitcher-collage-${Date.now()}.jpg`;
    link.href = exportCanvas.toDataURL('image/jpeg', settings.quality);
    link.click();
  };

  return (
    <div className="min-h-screen flex flex-col lg:flex-row bg-[#0B0E14] text-slate-100">
      {/* Sidebar - Controls */}
      <aside className="w-full lg:w-80 bg-[#161B22] border-r border-slate-800 overflow-y-auto p-6 space-y-8 scrollbar-hide h-screen hidden lg:block">
        <div className="flex items-center gap-3">
          <div className="p-2.5 bg-indigo-600 rounded-xl shadow-lg shadow-indigo-600/20">
            <LayoutGrid className="w-5 h-5 text-white" />
          </div>
          <h1 className="text-xl font-black tracking-tight text-white italic">STITCHER</h1>
        </div>

        <section className="space-y-6">
          <div className="space-y-4">
            <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500 flex items-center gap-2">
              <Settings2 className="w-3.5 h-3.5" /> 版面網格 Layout
            </h2>
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1.5">
                <label className="text-[10px] text-slate-400 font-bold ml-1">欄位 (Cols)</label>
                <input 
                  type="number" 
                  min="1" 
                  value={settings.columns} 
                  onChange={e => setSettings(s => ({ ...s, columns: Math.max(1, parseInt(e.target.value) || 1), rows: Math.ceil(images.length / (parseInt(e.target.value) || 1)) }))} 
                  className="w-full bg-[#0D1117] border border-slate-700 rounded-xl p-2.5 text-sm outline-none focus:border-indigo-500 transition-colors" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] text-slate-400 font-bold ml-1">列數 (Rows)</label>
                <input 
                  type="number" 
                  min="1" 
                  value={settings.rows} 
                  onChange={e => setSettings(s => ({ ...s, rows: Math.max(1, parseInt(e.target.value) || 1) }))} 
                  className="w-full bg-[#0D1117] border border-slate-700 rounded-xl p-2.5 text-sm outline-none focus:border-indigo-500 transition-colors" 
                />
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500">內部框架比例</h2>
            <div className="grid grid-cols-1 gap-2">
              {ASPECT_RATIO_PRESETS.map((p) => (
                <button 
                  key={p.label}
                  onClick={() => setSettings(s => ({ ...s, itemAspectRatio: p.value }))}
                  className={`flex items-center justify-between px-4 py-2.5 rounded-xl border transition-all text-xs ${
                    settings.itemAspectRatio === p.value 
                      ? 'bg-indigo-600 border-indigo-600 text-white font-bold' 
                      : 'bg-slate-800/50 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {p.label}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
             <div className="flex justify-between items-center">
              <h2 className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500">細節微調</h2>
            </div>

            <div className="space-y-4">
              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>間距 (Gap)</span>
                  <span>{settings.gap}px</span>
                </div>
                <input type="range" min="0" max="100" value={settings.gap} onChange={e => setSettings(s => ({ ...s, gap: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>圓角 (Radius)</span>
                  <span>{settings.borderRadius}px</span>
                </div>
                <input type="range" min="0" max="100" value={settings.borderRadius} onChange={e => setSettings(s => ({ ...s, borderRadius: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-[10px] font-bold text-slate-400 px-1">
                  <span>外距 (Padding)</span>
                  <span>{settings.padding}px</span>
                </div>
                <input type="range" min="0" max="150" value={settings.padding} onChange={e => setSettings(s => ({ ...s, padding: parseInt(e.target.value) }))} className="w-full h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" />
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[11px] font-bold uppercase tracking-[0.15em] text-slate-500 block">背景底色</label>
            <div className="flex gap-3 p-2 bg-[#0D1117] border border-slate-700 rounded-xl">
              <input type="color" value={settings.backgroundColor} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="w-10 h-10 bg-transparent border-none cursor-pointer rounded-lg overflow-hidden shrink-0" />
              <input type="text" value={settings.backgroundColor.toUpperCase()} onChange={e => setSettings(s => ({ ...s, backgroundColor: e.target.value }))} className="flex-1 bg-transparent border-none text-xs font-mono focus:outline-none uppercase text-slate-300" />
            </div>
          </div>
        </section>

        {selectedImage && (
          <section className="p-4 bg-indigo-500/10 rounded-2xl border border-indigo-500/20 space-y-4 animate-in slide-in-from-bottom-2">
            <div className="flex items-center justify-between">
              <h2 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center gap-2">
                <Move className="w-3.5 h-3.5" /> 影像調整
              </h2>
              <button onClick={() => setSelectedId(null)} className="text-slate-500 hover:text-white"><X className="w-4 h-4" /></button>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <button 
                onClick={() => updateImageTransform(selectedImage.id, { flipX: !selectedImage.transform.flipX })}
                className={`flex items-center justify-center gap-2 py-2 rounded-xl text-[10px] font-bold uppercase border transition-all ${
                  selectedImage.transform.flipX 
                    ? 'bg-indigo-600 border-indigo-600 text-white' 
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'
                }`}
              >
                <FlipHorizontal className="w-3.5 h-3.5" /> 水平鏡射
              </button>
              <button 
                onClick={() => updateImageTransform(selectedImage.id, { flipY: !selectedImage.transform.flipY })}
                className={`flex items-center justify-center gap-2 py-2 rounded-xl text-[10px] font-bold uppercase border transition-all ${
                  selectedImage.transform.flipY 
                    ? 'bg-indigo-600 border-indigo-600 text-white' 
                    : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'
                }`}
              >
                <FlipVertical className="w-3.5 h-3.5" /> 垂直鏡射
              </button>
            </div>

            <div className="space-y-3">
              <div className="flex justify-between text-[10px] font-bold text-slate-400">
                <span>縮放 Scale</span>
                <span>x{selectedImage.transform.scale.toFixed(2)}</span>
              </div>
              <input type="range" min="0.5" max="4" step="0.01" value={selectedImage.transform.scale} onChange={e => updateImageTransform(selectedImage.id, { scale: parseFloat(e.target.value) })} className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-indigo-400" />
              <button 
                onClick={() => updateImageTransform(selectedImage.id, { scale: 1, translateX: 0, translateY: 0, flipX: false, flipY: false })} 
                className="w-full py-2 bg-slate-800 hover:bg-slate-700 text-[10px] uppercase font-bold text-slate-300 transition rounded-lg flex items-center justify-center gap-2"
              >
                <RotateCcw className="w-3 h-3" /> 重設位置與鏡射
              </button>
            </div>
          </section>
        )}
      </aside>

      {/* Main Area */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden bg-[#0D1117]">
        <header className="px-6 py-4 bg-[#161B22] border-b border-slate-800 flex justify-between items-center z-10">
          <div className="flex items-center gap-4">
            <LayoutGrid className="w-5 h-5 text-indigo-500 lg:hidden" />
            <h2 className="font-black tracking-tight text-sm uppercase text-slate-400">畫布中心</h2>
            <div className="h-4 w-px bg-slate-800 hidden md:block" />
            <div className="hidden md:flex items-center gap-2 text-[11px] text-slate-500 font-medium">
              <span>{images.length} 張圖片</span>
              <ChevronRight className="w-3 h-3" />
              <span>{settings.columns} x {settings.rows} 網格</span>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <label className="cursor-pointer group">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex items-center gap-2 px-4 py-2.5 bg-slate-800 hover:bg-slate-700 border border-slate-700 rounded-full text-xs font-bold text-slate-300 transition-all active:scale-95">
                <Upload className="w-3.5 h-3.5" />
                <span>加入素材</span>
              </div>
            </label>
            <button 
              onClick={downloadCollage} 
              disabled={images.length === 0}
              className="flex items-center gap-2 px-6 py-2.5 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed rounded-full text-xs font-black text-white transition-all shadow-lg shadow-indigo-600/30 active:scale-95"
            >
              <Download className="w-4 h-4" />
              <span>輸出成品</span>
            </button>
          </div>
        </header>

        {/* Canvas Area */}
        <div className="flex-1 overflow-auto p-4 lg:p-12 flex items-center justify-center relative bg-[#0D1117] custom-scrollbar">
          {images.length === 0 ? (
            <div className="text-center space-y-6 max-w-sm">
              <div className="w-20 h-20 bg-[#161B22] rounded-3xl flex items-center justify-center mx-auto border border-slate-800 shadow-2xl">
                <ImageIcon className="w-8 h-8 text-slate-600" />
              </div>
              <div className="space-y-2">
                <h3 className="text-lg font-black text-white uppercase tracking-widest">點擊加入照片</h3>
                <p className="text-slate-500 text-xs px-6 leading-relaxed">上傳多張 JPG/PNG 素材，在下方橫幅拖拽調整順序，左側調整框架細節。</p>
              </div>
            </div>
          ) : (
            <div className="relative group max-h-full">
              <div className="shadow-[0_80px_160px_-40px_rgba(0,0,0,0.9)] rounded-md overflow-hidden border border-white/5 transition-transform duration-500">
                <canvas 
                  ref={canvasRef} 
                  onMouseDown={handleCanvasMouseDown}
                  onMouseMove={handleCanvasMouseMove}
                  onMouseUp={handleCanvasMouseUp}
                  onMouseLeave={handleCanvasMouseUp}
                  onTouchStart={handleCanvasMouseDown}
                  onTouchMove={handleCanvasMouseMove}
                  onTouchEnd={handleCanvasMouseUp}
                  style={{ cursor: isDraggingCanvas ? 'grabbing' : 'crosshair' }}
                  className="max-w-full max-h-[75vh] object-contain mx-auto select-none touch-none bg-black"
                />
              </div>
              <div className="absolute -top-12 right-0 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => { setImages([]); setSelectedId(null); }} className="flex items-center gap-2 px-4 py-2 bg-red-600/90 hover:bg-red-600 text-white text-[10px] font-black rounded-full shadow-2xl transition backdrop-blur-md uppercase">
                  <Trash2 className="w-3.5 h-3.5" /> 清空畫布
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Bottom Banner - Reorderable Thumbnails */}
        {images.length > 0 && (
          <div className="h-32 bg-[#161B22] border-t border-slate-800 px-6 py-4 flex gap-4 overflow-x-auto items-center scrollbar-hide relative shadow-[0_-20px_50px_rgba(0,0,0,0.3)]">
            <div className="shrink-0 flex items-center gap-2 mr-2">
              <GripHorizontal className="w-4 h-4 text-slate-600" />
              <span className="text-[10px] font-black text-slate-500 uppercase vertical-text">排序</span>
            </div>

            {images.map((img, index) => (
              <div 
                key={img.id} 
                draggable
                onDragStart={() => handleDragStart(index)}
                onDragOver={(e) => handleDragOver(e, index)}
                onDragEnd={handleDragEnd}
                className={`relative flex-shrink-0 group cursor-grab active:cursor-grabbing transition-all duration-300 ${
                  draggedThumbnailIdx === index ? 'opacity-30 scale-90' : 'opacity-100'
                }`}
              >
                <button
                  onClick={() => setSelectedId(img.id)}
                  className={`relative block h-16 w-16 overflow-hidden rounded-xl border-2 transition-all duration-300 ${
                    selectedId === img.id ? 'border-indigo-500 ring-4 ring-indigo-500/20 scale-105 shadow-xl' : 'border-slate-800 hover:border-slate-500'
                  }`}
                >
                  <img src={img.preview} alt="Thumb" className="h-full w-full object-cover select-none pointer-events-none" />
                </button>
                <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(img.id); }} 
                  className="absolute -top-2 -right-2 p-1.5 bg-slate-900 border border-slate-700 text-white rounded-full transition opacity-0 group-hover:opacity-100 scale-75 hover:bg-red-600 hover:border-red-600 shadow-xl"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            ))}

            <label className="flex-shrink-0 h-16 w-16 flex items-center justify-center border-2 border-dashed border-slate-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/5 cursor-pointer transition-all">
              <input type="file" multiple accept="image/jpeg,image/png" onChange={handleFileUpload} className="hidden" />
              <div className="flex flex-col items-center gap-1">
                <Upload className="w-4 h-4 text-slate-600" />
                <span className="text-[8px] font-bold text-slate-600">ADD</span>
              </div>
            </label>
          </div>
        )}
      </main>

      <style>{`
        .scrollbar-hide::-webkit-scrollbar { display: none; }
        .scrollbar-hide { -ms-overflow-style: none; scrollbar-width: none; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; }
        .vertical-text { writing-mode: vertical-rl; transform: rotate(180deg); }
      `}</style>
    </div>
  );
};

export default App;
